import React, { useEffect, useState } from "react";
import { Link } from "wouter";
import Layout from "@/components/layout/layout";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";

export default function AdminQueries() {
  const [queries, setQueries] = useState([]);

  useEffect(() => {
    fetch("http://localhost:5000/api/query")
      .then(res => res.json())
      .then(setQueries);
  }, []);

  const handleIgnore = async (id) => {
    await fetch(`http://localhost:5000/api/query/${id}/ignore`, { method: "PATCH" });
    setQueries(qs => qs.map(q => q._id === id ? { ...q, ignored: true, status: "Ignored" } : q));
  };

  return (
    <Layout>
      <div className="max-w-6xl mx-auto mt-8">
        <Card>
          <CardHeader>
            <CardTitle className="text-2xl text-primary">All Queries</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="overflow-x-auto">
              <table className="min-w-full border border-gray-200 rounded-lg">
                <thead>
                  <tr className="bg-gray-100 text-gray-700">
                    <th className="py-2 px-4 border-b">Query No</th>
                    <th className="py-2 px-4 border-b">Name</th>
                    <th className="py-2 px-4 border-b">Email</th>
                    <th className="py-2 px-4 border-b">Phone number</th>
                    <th className="py-2 px-4 border-b">Query</th>
                    <th className="py-2 px-4 border-b">Status</th>
                    <th className="py-2 px-4 border-b">Action</th>
                  </tr>
                </thead>
                <tbody>
                  {queries.map((q, i) => (
                    <tr key={q._id} className="hover:bg-gray-50">
                      <td className="py-2 px-4 border-b text-center">{i + 1}</td>
                      <td className="py-2 px-4 border-b">{q.name}</td>
                      <td className="py-2 px-4 border-b">{q.email}</td>
                      <td className="py-2 px-4 border-b">{q.mobile}</td>
                      <td className="py-2 px-4 border-b">{q.message}</td>
                      <td className="py-2 px-4 border-b text-center">
                        <span className={
                          q.ignored
                            ? "px-2 py-1 rounded bg-gray-300 text-gray-700 text-xs"
                            : q.replied
                            ? "px-2 py-1 rounded bg-green-100 text-green-700 text-xs"
                            : "px-2 py-1 rounded bg-yellow-100 text-yellow-700 text-xs"
                        }>
                          {q.ignored
                            ? "Ignored"
                            : q.replied
                            ? "Replied"
                            : "Not Replied"}
                        </span>
                      </td>
                      <td className="py-2 px-4 border-b text-center">
                        {!q.ignored && (
                          <div className="flex gap-2 justify-center">
                            <Link href={`/admin/query/${q._id}/answer`}>
                              <Button className="bg-primary text-white hover:bg-primary/90 px-3 py-1 rounded">
                                Answer
                              </Button>
                            </Link>
                            <Button
                              variant="outline"
                              className="bg-gray-200 text-gray-800 hover:bg-gray-300 px-3 py-1 rounded"
                              onClick={() => handleIgnore(q._id)}
                            >
                              Ignore
                            </Button>
                          </div>
                        )}
                      </td>
                    </tr>
                  ))}
                  {queries.length === 0 && (
                    <tr>
                      <td colSpan={7} className="py-4 text-center text-gray-500">
                        No queries found.
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </CardContent>
        </Card>
      </div>
    </Layout>
  );
}

server/paypal.js.content:
import {
  Client,
  Environment,
  LogLevel,
  OAuthAuthorizationController,
  OrdersController,
} from "@paypal/paypal-server-sdk";

const { PAYPAL_CLIENT_ID, PAYPAL_CLIENT_SECRET, PAYPAL_MODE } = process.env;

const paypalConfigured = Boolean(PAYPAL_CLIENT_ID && PAYPAL_CLIENT_SECRET);

if (!paypalConfigured) {
  console.log('[paypal] PayPal credentials not configured - PayPal features will be disabled');
}

const envMode = (PAYPAL_MODE || (process.env.NODE_ENV === 'production' ? 'production' : 'sandbox')).toLowerCase();

const environment = envMode === 'production' ? Environment.Production : Environment.Sandbox;

let client = null;
let ordersController = null;
let oAuthAuthorizationController = null;

if (paypalConfigured) {
  client = new Client({
    clientCredentialsAuthCredentials: {
      oAuthClientId: PAYPAL_CLIENT_ID,
      oAuthClientSecret: PAYPAL_CLIENT_SECRET,
    },
    timeout: 0,
    environment,
    logging: {
      logLevel: LogLevel.Info,
      logRequest: {
        logBody: true,
      },
      logResponse: {
        logHeaders: true,
      },
    },
  });

  ordersController = new OrdersController(client);
  oAuthAuthorizationController = new OAuthAuthorizationController(client);
}

export async function getClientToken() {
  if (!paypalConfigured) {
    throw new Error('PayPal is not configured. Please set PAYPAL_CLIENT_ID and PAYPAL_CLIENT_SECRET environment variables.');
  }

  try {
    const auth = Buffer.from(`${PAYPAL_CLIENT_ID}:${PAYPAL_CLIENT_SECRET}`).toString("base64");

    const { result } = await oAuthAuthorizationController.requestToken(
      {
        authorization: `Basic ${auth}`,
      },
      { intent: "sdk_init", response_type: "client_token" },
    );

    return result?.accessToken;
  } catch (err) {
    console.error('[paypal] Failed to fetch client token.', {
      message: err?.message,
      statusCode: err?.request?.statusCode || err?.statusCode,
      body: err?.request?.body || err?.body || err?.result,
    });
    throw err;
  }
}

export async function createPaypalOrder(req, res) {
  if (!paypalConfigured) {
    return res.status(503).json({ error: "PayPal is not configured on this server." });
  }

  try {
    const { amount, currency, intent } = req.body;

    if (!amount || isNaN(parseFloat(amount)) || parseFloat(amount) <= 0) {
      return res
        .status(400)
        .json({
          error: "Invalid amount. Amount must be a positive number.",
        });
    }

    if (!currency) {
      return res
        .status(400)
        .json({ error: "Invalid currency. Currency is required." });
    }

    if (!intent) {
      return res
        .status(400)
        .json({ error: "Invalid intent. Intent is required." });
    }

    const collect = {
      body: {
        intent: intent,
        purchaseUnits: [
          {
            amount: {
              currencyCode: currency,
              value: amount,
            },
          },
        ],
      },
      prefer: "return=minimal",
    };

    const { body, ...httpResponse } =
      await ordersController.createOrder(collect);

    const jsonResponse = JSON.parse(String(body));
    const httpStatusCode = httpResponse.statusCode;

    res.status(httpStatusCode).json(jsonResponse);
  } catch (error) {
    console.error("Failed to create order:", error);
    res.status(500).json({ error: "Failed to create order." });
  }
}

export async function capturePaypalOrder(req, res) {
  if (!paypalConfigured) {
    return res.status(503).json({ error: "PayPal is not configured on this server." });
  }

  try {
    const { orderID } = req.params;
    const collect = {
      id: orderID,
      prefer: "return=minimal",
    };

    const { body, ...httpResponse } =
      await ordersController.captureOrder(collect);

    const jsonResponse = JSON.parse(String(body));
    const httpStatusCode = httpResponse.statusCode;

    res.status(httpStatusCode).json(jsonResponse);
  } catch (error) {
    console.error("Failed to capture order:", error);
    res.status(500).json({ error: "Failed to capture order." });
  }
}

export async function loadPaypalDefault(req, res) {
  if (!paypalConfigured) {
    return res.status(503).json({ error: "PayPal is not configured on this server.", configured: false });
  }

  try {
    const clientToken = await getClientToken();
    res.json({
      clientToken,
      mode: envMode,
      configured: true
    });
  } catch (error) {
    console.error('[paypal] Error loading PayPal:', error);
    res.status(500).json({ error: "Failed to load PayPal configuration." });
  }
}

