import { 
  User, Employee, Payroll, LeaveRequest, Attendance, Profile, Loan, EMI, getNextSequence
} from "../shared/mongoose-schema.js";
import mongoose from "mongoose";
import session from "express-session";
import MongoStore from "connect-mongo";

export class DatabaseStorage {
  constructor() {
    const skipDb = (process.env.SKIP_DB || 'false').toLowerCase() === 'true';

    if (!skipDb && !process.env.MONGODB_URL) {
      throw new Error('MONGODB_URL is missing. Add MONGODB_URL to your environment variables.');
    }

    if (!skipDb) {
      this.sessionStore = MongoStore.create({
        client: mongoose.connection.getClient(),
        touchAfter: 24 * 3600 // lazy session update
      });
    } else {
      this.sessionStore = null;
    }
  }

  // Users
  async getUser(id) {
    try {
      const user = await User.findById(id);
      return user ? user.toObject() : undefined;
    } catch (error) {
      console.error('Error getting user:', error);
      return undefined;
    }
  }

  async getUserByUsername(username) {
    try {
      const user = await User.findOne({ username });
      return user ? user.toObject() : undefined;
    } catch (error) {
      console.error('Error getting user by username:', error);
      return undefined;
    }
  }

  async createUser(insertUser) {
    try {
      const user = new User(insertUser);
      await user.save();
      return user.toObject();
    } catch (error) {
      console.error('Error creating user:', error);
      throw error;
    }
  }

  async updateUserPassword(id, newPassword) {
    try {
      const user = await User.findByIdAndUpdate(
        id, 
        { password: newPassword }, 
        { new: true }
      );
      return user ? user.toObject() : undefined;
    } catch (error) {
      console.error('Error updating user password:', error);
      throw error;
    }
  }

  // Employees
  async getEmployee(id) {
    try {
      const employee = await Employee.findById(id);
      return employee ? employee.toObject() : undefined;
    } catch (error) {
      console.error('Error getting employee:', error);
      return undefined;
    }
  }

  async getEmployeeByUserId(userId) {
    try {
      const employee = await Employee.findOne({ userId });
      return employee ? employee.toObject() : undefined;
    } catch (error) {
      console.error('Error getting employee by user ID:', error);
      return undefined;
    }
  }

  async getEmployeeByEmail(email) {
    try {
      const employee = await Employee.findOne({ email });
      return employee ? employee.toObject() : undefined;
    } catch (error) {
      console.error('Error getting employee by email:', error);
      return undefined;
    }
  }

  async getUserByEmail(email) {
    try {
      const employee = await Employee.findOne({ email });
      if (!employee) return undefined;
      const user = await User.findById(employee.userId);
      return user ? user.toObject() : undefined;
    } catch (error) {
      console.error('Error getting user by email:', error);
      return undefined;
    }
  }

  async getUserByGoogleId(googleId) {
    try {
      const user = await User.findOne({ googleId });
      return user ? user.toObject() : undefined;
    } catch (error) {
      console.error('Error getting user by Google ID:', error);
      return undefined;
    }
  }



  async getAllEmployees() {
    try {
      const employees = await Employee.find().sort({ createdAt: -1 });
      return employees.map(emp => emp.toObject());
    } catch (error) {
      console.error('Error getting all employees:', error);
      return [];
    }
  }

  async createEmployee(insertEmployee) {
    try {
      const nextSeq = await getNextSequence('employeeId');
      const employeeId = 'E' + String(nextSeq).padStart(2, '0');

      const employee = new Employee({
        ...insertEmployee,
        employeeId
      });
      await employee.save();
      return employee.toObject();
